// PLACEHOLDER - returns empty until mdk eval emits OTel metrics.
// When instrumented, expected schema:
//   AppMetrics where Name in ("mdk.eval.pass", "mdk.eval.fail")
//   Properties["agent"] / Properties["eval_set"] carry the partitions.
AppMetrics
| where Name startswith "mdk.eval."
| extend agent = tostring(Properties["agent"]), evalSet = tostring(Properties["eval_set"])
| summarize Pass = sumif(Sum, Name == "mdk.eval.pass"), Fail = sumif(Sum, Name == "mdk.eval.fail") by agent, evalSet, bin(TimeGenerated, 1h)
| extend PassPct = iff((Pass + Fail) == 0, 0.0, round(100.0 * Pass / (Pass + Fail), 2))
| project TimeGenerated, agent, evalSet, PassPct
| order by TimeGenerated asc
